proof fn phi_1_lemma_write_seq_first_external_body(m: PTMem, writes: Seq<(usize, usize)>)
    requires
        writes.len() > 0,
    ensures
        m.write_seq(writes) == m.write(writes[0].0, writes[0].1).write_seq(writes.drop_first()),
{
    PTMem::lemma_write_seq_first(m, writes);
}

proof fn phi_2_writeback_preserves_writer_mem_via_external(pre: State, post: State, c: Constants, core: Core, lbl: Lbl)
    requires
        pre.inv_sbuf_facts(c),
        step_Writeback(pre, post, c, core, lbl),
    ensures
        post.writer_mem() == pre.writer_mem(),
{
    assert(post.writes.core == core);
    PTMem::lemma_write_seq_first(pre.pt_mem, pre.sbuf[core]);
}
